const query = $input.first().json.query || {};
const VERIFY_TOKEN = 'myverifytoken123';

const mode = query['hub.mode'];
const token = query['hub.verify_token'];
const challenge = query['hub.challenge'];

if (mode === 'subscribe' && token === VERIFY_TOKEN) {
  return [{ json: { challenge: challenge, statusCode: 200 } }];
}

return [{ json: { error: 'Verification failed', statusCode: 403, challenge: '' } }];

// =================================================================
// WhatsApp Commerce Bot — State Machine
// =================================================================

// --- Configuration ---
const PHONE_NUMBER_ID = '1099754263228951';
const STORE_NAME      = 'LocalMart';
const DELIVERY_FEE    = 2.00;
const TAX_RATE        = 0.08;

// --- Product Catalog ---
const PRODUCTS = {
  'prod_1': { name: '🍞 Bread',        price: 2.50, unit: 'loaf'        },
  'prod_2': { name: '🥛 Milk',         price: 1.80, unit: '1L bottle'   },
  'prod_3': { name: '🥚 Eggs',         price: 3.50, unit: 'dozen'       },
  'prod_4': { name: '🍚 Rice',         price: 2.00, unit: '1kg bag'     },
  'prod_5': { name: '🧂 Sugar',        price: 1.50, unit: '1kg bag'     },
  'prod_6': { name: '🫙 Cooking Oil',  price: 3.00, unit: '1L bottle'   },
  'prod_7': { name: '💧 Bottled Water',price: 1.00, unit: '500ml bottle'},
  'prod_8': { name: '🧼 Soap',         price: 2.00, unit: 'bar'         }
};

// --- Parse incoming WhatsApp webhook ---
const body     = $input.first().json.body;
const messages = body?.entry?.[0]?.changes?.[0]?.value?.messages;
const contacts = body?.entry?.[0]?.changes?.[0]?.value?.contacts;

if (!messages || messages.length === 0) {
  return [{ json: { skip: true, reason: 'No messages (status update or other event)' } }];
}

const message     = messages[0];
const contact     = contacts?.[0];
const from        = message.from;
const messageType = message.type;
const contactName = contact?.profile?.name || 'Customer';

let messageText = '';
if (messageType === 'text') {
  messageText = message.text?.body?.trim() || '';
} else if (messageType === 'interactive') {
  const iType = message.interactive?.type;
  if (iType === 'button_reply') {
    messageText = message.interactive.button_reply?.id || '';
  } else if (iType === 'list_reply') {
    messageText = message.interactive.list_reply?.id || '';
  }
} else {
  messageText = '__unsupported__';
}

// --- Session management ---
const staticData = $getWorkflowStaticData('global');
if (!staticData.sessions)        staticData.sessions = {};
if (!staticData.completedOrders) staticData.completedOrders = [];

const now = Date.now();
for (const phone of Object.keys(staticData.sessions)) {
  const s = staticData.sessions[phone];
  if (s.lastActivity && (now - new Date(s.lastActivity).getTime()) > 86_400_000) {
    delete staticData.sessions[phone];
  }
}

let session = staticData.sessions[from] || {
  state: 'initial',
  cart: [],
  name: '',
  location: '',
  selectedProduct: null,
  invoice: null,
  createdAt: new Date().toISOString()
};
session.lastActivity = new Date().toISOString();

// --- Global commands ---
const textLower = messageText.toLowerCase().trim();
const RESET_CMDS = ['menu', 'restart', 'start', 'hi', 'hello', 'hola', '/start', '0'];
const HELP_CMDS  = ['help', 'ayuda', '?'];

let payload = null;

if (messageText === '__unsupported__') {
  payload = mkText(from, 'I can only read text messages and menu taps.\n\nType *MENU* to browse products or *HELP* for assistance.');

} else if (HELP_CMDS.includes(textLower)) {
  payload = mkText(from,
    '*Help & Support*\n\n' +
    '*How to order:*\n' +
    '1. Type MENU or say hello\n' +
    '2. Pick a product from the list\n' +
    '3. Enter the quantity you want\n' +
    '4. Add more items or proceed to checkout\n' +
    '5. Enter your name and delivery address\n' +
    '6. Review your invoice and confirm\n\n' +
    '*Commands:*\n' +
    '- *MENU* - Browse products / restart\n' +
    '- *HELP* - Show this message\n\n' +
    'Type *MENU* to start shopping!'
  );

} else if (RESET_CMDS.includes(textLower) || session.state === 'initial') {
  session.state           = 'awaiting_menu';
  session.cart            = [];
  session.selectedProduct = null;
  session.name            = '';
  session.location        = '';
  session.invoice         = null;
  payload = mkWelcome(from, contactName);

} else {
  switch (session.state) {

    case 'awaiting_menu': {
      if (PRODUCTS[messageText]) {
        const prod = PRODUCTS[messageText];
        session.selectedProduct = messageText;
        session.state = 'awaiting_quantity';
        payload = mkText(from,
          `*${prod.name}* selected!\n\n` +
          `Price: *$${prod.price.toFixed(2)}* per ${prod.unit}\n\n` +
          `How many ${prod.unit}s would you like?\n` +
          `(Enter a whole number between 1 and 99)`
        );
      } else {
        payload = mkMenu(from, 'Please choose a product from the list:');
      }
      break;
    }

    case 'awaiting_quantity': {
      const qty = parseInt(messageText, 10);
      if (!isNaN(qty) && qty >= 1 && qty <= 99) {
        const prodId = session.selectedProduct;
        const prod   = PRODUCTS[prodId];
        if (!prod) {
          session.state = 'awaiting_menu';
          payload = mkWelcome(from, contactName);
          break;
        }
        const existIdx = session.cart.findIndex(i => i.id === prodId);
        if (existIdx >= 0) {
          session.cart[existIdx].quantity += qty;
          session.cart[existIdx].subtotal  = session.cart[existIdx].quantity * session.cart[existIdx].price;
        } else {
          session.cart.push({ id: prodId, name: prod.name, price: prod.price, unit: prod.unit, quantity: qty, subtotal: prod.price * qty });
        }
        session.selectedProduct = null;
        session.state = 'awaiting_cart_action';
        payload = mkCart(from, session.cart);
      } else {
        payload = mkText(from, 'Invalid quantity. Please enter a number between *1* and *99*:');
      }
      break;
    }

    case 'awaiting_cart_action': {
      if (messageText === 'action_add_more') {
        session.state = 'awaiting_menu';
        payload = mkMenu(from, 'Select another product to add to your cart:');
      } else if (messageText === 'action_checkout') {
        if (session.cart.length === 0) {
          session.state = 'awaiting_menu';
          payload = mkWelcome(from, contactName);
        } else {
          session.state = 'awaiting_name';
          payload = mkText(from, '*Delivery Details*\n\nPlease enter your *full name*:');
        }
      } else if (messageText === 'action_clear') {
        session.cart  = [];
        session.state = 'awaiting_menu';
        payload = mkText(from, 'Cart cleared!\n\nType *MENU* to start a new order.');
      } else {
        payload = mkCart(from, session.cart);
      }
      break;
    }

    case 'awaiting_name': {
      const safeName = messageText.replace(/[<>"]/g, '');
      if (safeName.length >= 2 && safeName.length <= 100 && !safeName.startsWith('action_') && !safeName.startsWith('prod_') && !safeName.startsWith('confirm_')) {
        session.name  = safeName;
        session.state = 'awaiting_location';
        payload = mkText(from,
          `Thank you, *${safeName}*!\n\n` +
          `Please enter your *delivery address*:\n` +
          `(Street name, area, or any landmarks)`
        );
      } else {
        payload = mkText(from, 'Please enter a valid name (2-100 characters):');
      }
      break;
    }

    case 'awaiting_location': {
      const safeAddr = messageText.replace(/[<>"]/g, '');
      if (safeAddr.length >= 5 && safeAddr.length <= 500 && !safeAddr.startsWith('action_') && !safeAddr.startsWith('prod_') && !safeAddr.startsWith('confirm_')) {
        session.location = safeAddr;

        const subtotal = session.cart.reduce((s, i) => s + i.subtotal, 0);
        const tax      = subtotal * TAX_RATE;
        const total    = subtotal + DELIVERY_FEE + tax;

        session.invoice = {
          orderNumber: `ORD-${Date.now()}-${Math.floor(Math.random() * 9000) + 1000}`,
          subtotal:    subtotal.toFixed(2),
          deliveryFee: DELIVERY_FEE.toFixed(2),
          taxRate:     (TAX_RATE * 100).toFixed(0),
          tax:         tax.toFixed(2),
          total:       total.toFixed(2),
          createdAt:   new Date().toISOString()
        };

        session.state = 'awaiting_confirmation';
        payload = mkInvoice(from, session);
      } else {
        payload = mkText(from, 'Please enter a valid delivery address (at least 5 characters):');
      }
      break;
    }

    case 'awaiting_confirmation': {
      if (messageText === 'confirm_yes') {
        const orderNum = session.invoice.orderNumber;
        staticData.completedOrders.push({
          orderNumber: orderNum,
          from,
          name:        session.name,
          location:    session.location,
          cart:        JSON.parse(JSON.stringify(session.cart)),
          invoice:     JSON.parse(JSON.stringify(session.invoice)),
          completedAt: new Date().toISOString()
        });
        if (staticData.completedOrders.length > 500) {
          staticData.completedOrders = staticData.completedOrders.slice(-500);
        }
        session.state           = 'initial';
        session.cart            = [];
        session.name            = '';
        session.location        = '';
        session.invoice         = null;
        session.selectedProduct = null;
        payload = mkConfirmed(from, orderNum);

      } else if (messageText === 'confirm_no') {
        session.state           = 'initial';
        session.cart            = [];
        session.name            = '';
        session.location        = '';
        session.invoice         = null;
        session.selectedProduct = null;
        payload = mkText(from,
          '*Order Cancelled*\n\n' +
          'No charges were made.\n\n' +
          'Type *MENU* to start a new order anytime!'
        );
      } else {
        payload = mkInvoice(from, session);
      }
      break;
    }

    default: {
      session.state = 'initial';
      session.cart  = [];
      payload = mkWelcome(from, contactName);
    }
  }
}

staticData.sessions[from] = session;

// =================================================================
// MESSAGE BUILDER HELPERS
// =================================================================

function mkWelcome(to, name) {
  return {
    messaging_product: 'whatsapp',
    recipient_type: 'individual',
    to,
    type: 'interactive',
    interactive: {
      type: 'list',
      header: { type: 'text', text: `Welcome to ${STORE_NAME}!` },
      body: {
        text:
          `Hello *${name}*!\n\n` +
          `Welcome to *${STORE_NAME}* - your neighborhood store.\n\n` +
          `We deliver fresh groceries and household items right to your door!\n\n` +
          `Browse our products below to get started:`
      },
      footer: { text: 'Type HELP for assistance | MENU to restart' },
      action: {
        button: 'Browse Products',
        sections: [
          {
            title: 'Food & Beverages',
            rows: [
              { id: 'prod_1', title: 'Bread',  description: 'Fresh baked loaf - $2.50' },
              { id: 'prod_2', title: 'Milk',   description: 'Whole milk, 1L - $1.80' },
              { id: 'prod_3', title: 'Eggs',   description: 'Farm fresh, dozen - $3.50' },
              { id: 'prod_4', title: 'Rice',   description: 'Premium quality, 1kg - $2.00' },
              { id: 'prod_5', title: 'Sugar',  description: 'White refined, 1kg - $1.50' }
            ]
          },
          {
            title: 'Household Items',
            rows: [
              { id: 'prod_6', title: 'Cooking Oil',   description: 'Vegetable oil, 1L - $3.00' },
              { id: 'prod_7', title: 'Bottled Water', description: 'Purified, 500ml - $1.00' },
              { id: 'prod_8', title: 'Soap',          description: 'Antibacterial bar - $2.00' }
            ]
          }
        ]
      }
    }
  };
}

function mkMenu(to, headerText) {
  return {
    messaging_product: 'whatsapp',
    recipient_type: 'individual',
    to,
    type: 'interactive',
    interactive: {
      type: 'list',
      header: { type: 'text', text: headerText || 'Product Menu' },
      body: { text: 'Select a product to add to your cart:' },
      footer: { text: 'Type MENU to clear cart and start over' },
      action: {
        button: 'Choose Product',
        sections: [
          {
            title: 'Food & Beverages',
            rows: [
              { id: 'prod_1', title: 'Bread',  description: 'Fresh baked loaf - $2.50' },
              { id: 'prod_2', title: 'Milk',   description: 'Whole milk, 1L - $1.80' },
              { id: 'prod_3', title: 'Eggs',   description: 'Farm fresh, dozen - $3.50' },
              { id: 'prod_4', title: 'Rice',   description: 'Premium quality, 1kg - $2.00' },
              { id: 'prod_5', title: 'Sugar',  description: 'White refined, 1kg - $1.50' }
            ]
          },
          {
            title: 'Household Items',
            rows: [
              { id: 'prod_6', title: 'Cooking Oil',   description: 'Vegetable oil, 1L - $3.00' },
              { id: 'prod_7', title: 'Bottled Water', description: 'Purified, 500ml - $1.00' },
              { id: 'prod_8', title: 'Soap',          description: 'Antibacterial bar - $2.00' }
            ]
          }
        ]
      }
    }
  };
}

function mkCart(to, cart) {
  let lines = '*Your Shopping Cart:*\n\n';
  cart.forEach((item, i) => {
    lines += `${i + 1}. ${item.name}\n`;
    lines += `   ${item.quantity} x $${item.price.toFixed(2)} = *$${item.subtotal.toFixed(2)}*\n\n`;
  });
  const subtotal = cart.reduce((s, i) => s + i.subtotal, 0);
  lines += `---\n`;
  lines += `*Subtotal: $${subtotal.toFixed(2)}*\n`;
  lines += `(Delivery & tax added at checkout)\n\n`;
  lines += `What would you like to do?`;
  return {
    messaging_product: 'whatsapp',
    recipient_type: 'individual',
    to,
    type: 'interactive',
    interactive: {
      type: 'button',
      body: { text: lines },
      action: {
        buttons: [
          { type: 'reply', reply: { id: 'action_add_more', title: 'Add More'    } },
          { type: 'reply', reply: { id: 'action_checkout', title: 'Checkout'    } },
          { type: 'reply', reply: { id: 'action_clear',    title: 'Clear Cart'  } }
        ]
      }
    }
  };
}

function mkInvoice(to, session) {
  const { cart, invoice, name, location } = session;
  let txt = `*ORDER INVOICE*\n\n`;
  txt += `Order: *${invoice.orderNumber}*\n`;
  txt += `Name: *${name}*\n`;
  txt += `Deliver to: *${location}*\n\n`;
  txt += `*Items Ordered:*\n`;
  cart.forEach(item => {
    txt += `- ${item.name} x${item.quantity}\n`;
    txt += `  $${item.price.toFixed(2)} x ${item.quantity} = *$${item.subtotal.toFixed(2)}*\n`;
  });
  txt += `\n---\n`;
  txt += `Subtotal:    $${invoice.subtotal}\n`;
  txt += `Delivery:    $${invoice.deliveryFee}\n`;
  txt += `Tax (${invoice.taxRate}%):  $${invoice.tax}\n`;
  txt += `---\n`;
  txt += `*TOTAL: $${invoice.total}*\n\n`;
  txt += `Est. delivery: *2-4 hours*\n`;
  txt += `Payment: *Cash on delivery*\n\n`;
  txt += `Please review and confirm your order:`;
  return {
    messaging_product: 'whatsapp',
    recipient_type: 'individual',
    to,
    type: 'interactive',
    interactive: {
      type: 'button',
      header: { type: 'text', text: 'Your Invoice' },
      body:   { text: txt },
      footer: { text: 'Free cancellation before dispatch' },
      action: {
        buttons: [
          { type: 'reply', reply: { id: 'confirm_yes', title: 'Confirm Order' } },
          { type: 'reply', reply: { id: 'confirm_no',  title: 'Cancel Order'  } }
        ]
      }
    }
  };
}

function mkConfirmed(to, orderNumber) {
  return {
    messaging_product: 'whatsapp',
    recipient_type: 'individual',
    to,
    type: 'text',
    text: {
      body:
        `*Order Confirmed!*\n\n` +
        `Thank you for shopping at *${STORE_NAME}*!\n\n` +
        `Order #: *${orderNumber}*\n` +
        `Estimated delivery: *2-4 hours*\n` +
        `Payment: *Cash on delivery*\n\n` +
        `Our delivery team will call you shortly.\n\n` +
        `Need help? Type *HELP*\n` +
        `New order? Type *MENU*\n\n` +
        `Thank you! We appreciate your business.`
    }
  };
}

function mkText(to, bodyText) {
  return {
    messaging_product: 'whatsapp',
    recipient_type: 'individual',
    to,
    type: 'text',
    text: { body: bodyText }
  };
}

return [{
  json: {
    skip:            false,
    from,
    phoneNumberId:   PHONE_NUMBER_ID,
    whatsappPayload: payload,
    sessionState:    session.state,
    cartCount:       session.cart.length
  }
}];
